mapper.select:
SELECT l.log_code AS logCode, l.project_code AS projectCode, p.project_name AS projectName, l.user_code AS userCode, u.name AS userName, l.action_type AS actionType, l.target_type AS targetType, l.target_code AS targetCode, l.created_at AS createdAt, l.meta AS meta, COALESCE(i.title, n.title) AS title FROM logs l JOIN projects p ON p.project_code = l.project_code LEFT JOIN users u ON u.user_code = l.user_code
LEFT JOIN issues i ON l.target_type = 'ISSUE' AND i.issue_code = l.target_code
LEFT JOIN notices n ON l.target_type = 'NOTICE' AND n.notice_code = l.target_code
/* 로그인 사용자가 속한 프로젝트만 (+ 관리자면 종료(OD3)까지) */ JOIN vw_user_auth a ON a.project_code = l.project_code AND a.user_code = #{loginUserCode}
WHERE 1=1 AND ( (a.admin_ck = 'Y' AND a.status IN ('OD1','OD3')) OR (a.admin_ck = 'N' AND a.status = 'OD1') )
AND l.project_code = #{cond.projectCode}
AND l.user_code = #{cond.userCode}
AND l.created_at >= #{cond.fromDate}
AND l.created_at < (#{cond.toDate} + 1)
AND l.target_type IN
#{t}
ORDER BY l.created_at DESC, l.log_code DESC
